import React, { useState, useEffect, useCallback } from 'react';

const EditCombinedMaterial = ({
  materialId,
  onClose,
  fetchAPI,
  apiBaseUrl,
  onMaterialEdited,
}) => {
  const [materialData, setMaterialData] = useState({});
  const [error, setError] = useState(null);

  const fetchMaterialData = useCallback(async () => {
    try {
      const data = await fetchAPI(`${apiBaseUrl}/combinedMaterials/${materialId}`);
      setMaterialData(data);
    } catch (error) {
      setError(error.message);
    }
  }, [apiBaseUrl, fetchAPI, materialId]);

  useEffect(() => {
    fetchMaterialData();
  }, [fetchMaterialData]);

  const handleUpdateMaterial = async () => {
    try {
      // Directly call fetchAPI without assigning the response to a variable
      await fetchAPI(`${apiBaseUrl}/combinedMaterials/${materialId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(materialData),
      });
      onClose(); // Close the edit form after successful update
      onMaterialEdited(); // Notify the parent component to refresh the material list
    } catch (error) {
      setError(error.message);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setMaterialData((prevData) => ({
      ...prevData,
      [name]: value,
    }));
  };

  return (
    <div className="edit-combined-material">
      <h3>Edit Combined Material</h3>
      {error && <div>Error: {error}</div>}
      <form>
        <div className="form-group">
          <label htmlFor="name">Name</label>
          <input
            type="text"
            id="name"
            name="name"
            value={materialData.name || ''}
            onChange={handleChange}
          />
        </div>
        <div className="form-group">
          <label htmlFor="description">Description</label>
          <textarea
            id="description"
            name="description"
            value={materialData.description || ''}
            onChange={handleChange}
          />
        </div>
        <button type="button" onClick={handleUpdateMaterial}>
          Update Material
        </button>
        <button type="button" onClick={onClose}>
          Cancel
        </button>
      </form>
    </div>
  );
};

export default EditCombinedMaterial;
